// JavaScript
import "@maersk-global/mds-components-core/mc-multi-select";
import icons from '@maersk-global/icons/metadata/metadata.json';

const select = document.querySelector('mc-multi-select');
const options = icons.map((icon) => ({
  label: icon.name,
  value: icon.id,
  icon: icon.name,
  disabled: Math.random() < 0.2,
  group: icon.name.substring(0, 1).toUpperCase(),
}));
const availableOptions = options.filter((option) => !option.disabled);
const value = [availableOptions[0].value, availableOptions[1].value, availableOptions[5].value];
select.data = options;
select.value = value;

